const body = $json.body ?? $json ?? {};
const payload = body.data ?? body.event_data ?? body;
const message = payload.message && typeof payload.message === 'object' ? payload.message : {};
const sender = payload.sender && typeof payload.sender === 'object' ? payload.sender : {};
const recipient = payload.recipient && typeof payload.recipient === 'object' ? payload.recipient : {};

const rawText = payload.text ?? payload.content ?? payload.message_text ?? message.text ?? '';
const text = String(rawText || '').trim();
const mentionUserIdsFromText = Array.from(
  text.matchAll(/(?:\[@\s*|@)(\d{5,})(?:\])?/g),
  (match) => String(match[1] || '').trim()
).filter(Boolean);
const mentionSources = [
  payload.mentions,
  payload.message_mentions,
  payload.mention_data,
  message.mentions,
  message.message_mentions,
  message.mention_data,
];
const mentionUserIdsFromPayload = [];
for (const source of mentionSources) {
  if (!source) continue;
  const items = Array.isArray(source) ? source : [source];
  for (const item of items) {
    const userId = String(item?.uid ?? item?.user_id ?? item?.id ?? item?.userid ?? '').trim();
    if (userId) mentionUserIdsFromPayload.push(userId);
  }
}
const mentionUserIds = [...new Set([...mentionUserIdsFromPayload, ...mentionUserIdsFromText])];
const eventName = String(body.event_name ?? body.event ?? payload.event_name ?? payload.event_type ?? '').trim();
const loweredEvent = eventName.toLowerCase();

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s\/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const normalizedText = normalizeText(text);

let normalizedEventType = 'unknown';
if (loweredEvent.includes('join') || loweredEvent.includes('invite')) {
  normalizedEventType = 'member_joined';
} else if (loweredEvent.includes('remove') || loweredEvent.includes('leave')) {
  normalizedEventType = 'member_removed';
} else if (loweredEvent.includes('role') || loweredEvent.includes('admin')) {
  normalizedEventType = 'role_changed';
} else if (text || loweredEvent.includes('message') || loweredEvent.includes('group_text')) {
  normalizedEventType = 'group_message';
}

const looksLikeOperationalMessage = [
  /^\//,
  /(?:^|\s)(?:ticket|don)(?:\s|$)/,
  /ticket ao|ticket ảo/,
  /help|huong dan|co lenh gi|xem lenh|menu/,
  /xem thanh vien|danh sach thanh vien|danh sach member|member cho duyet|pending member|ai dang cho duyet|xem pending|xem member/,
  /phe duyet|duyet member|duyet thanh vien|approve member|approve thanh vien|cho vao|kich hoat member|kich hoat thanh vien/,
  /(?:^|\s)duyet(?:\s|$)/,
  /them thanh vien|moi thanh vien|add member|invite member|moi vao nhom|them nguoi vao nhom|link vao nhom|cach them thanh vien/,
  /xem tat ca(?:\s+cac)?(?:\s+(?:don|ticket))?|tat ca(?:\s+cac)?(?:\s+(?:don|ticket))?|danh sach (?:don|ticket)|xem het(?:\s+cac)?\s+(?:don|ticket)|xem toan bo(?:\s+cac)?\s+(?:don|ticket)|list ticket/,
  /(?:^|\s)reject(?:\s|$)|tu choi|loai bo lead|loai lead|huy lead/,
  /them pho nhom|lam pho nhom|bo nhiem pho nhom|len pho nhom|them admin|add admin|them quan tri|cap quyen pho nhom/,
  /xoa pho nhom|go pho nhom|bo pho nhom|ha pho nhom|xoa admin|bo admin|remove admin|remove deputy|go quyen pho nhom|bo quyen pho nhom|ha quyen pho nhom/,
].some((pattern) => pattern.test(normalizedText));

const shouldProcessGroupMessage = normalizedEventType === 'group_message' && Boolean(text);

const oaId = String(payload.oa_id ?? body.oa_id ?? body.app_id ?? '').trim();
const groupId = String(payload.group_id ?? payload.thread_id ?? recipient.id ?? body.group_id ?? '').trim();
const senderId = String(payload.sender_id ?? payload.user_id ?? payload.from_id ?? payload.actor_id ?? sender.id ?? '').trim();
const senderDisplayName = String(payload.display_name ?? payload.sender_name ?? payload.actor_name ?? sender.display_name ?? sender.name ?? '').trim();
const messageId = String(payload.message_id ?? payload.msg_id ?? body.message_id ?? message.msg_id ?? message.id ?? '').trim();

return [{
  json: {
    oa_id: oaId,
    group_id: groupId,
    sender_id: senderId,
    sender_display_name: senderDisplayName,
    message_id: messageId,
    source_event_id: messageId || [groupId, senderId, Date.now()].filter(Boolean).join(':'),
    event_name: eventName,
    normalized_event_type: normalizedEventType,
    text,
    mention_user_ids: mentionUserIds,
    should_route_command: shouldProcessGroupMessage,
    should_process_message: shouldProcessGroupMessage,
    looks_like_operational_message: looksLikeOperationalMessage,
    raw_payload: body,
  },
}];

const originalText = String($json.text || '').trim();
const isSlashCommand = originalText.startsWith('/');
const slashNormalized = isSlashCommand ? originalText.replace(/^\/+/, '').trim() : '';
const slashTokens = slashNormalized ? slashNormalized.split(/\s+/) : [];
const rawSlashCommand = isSlashCommand ? String(slashTokens.shift() || '').toLowerCase() : '';
const slashArgs = slashTokens;
const slashArgText = slashArgs.join(' ').trim();
const mentionUserIds = [...new Set([
  ...((Array.isArray($json.mention_user_ids) ? $json.mention_user_ids : []).map((value) => String(value || '').trim()).filter(Boolean)),
  ...Array.from(originalText.matchAll(/(?:\[@\s*|@)(\d{5,})(?:\])?/g), (match) => String(match[1] || '').trim()).filter(Boolean),
])];
const firstMentionUserId = mentionUserIds[0] || '';

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s\/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const normalizedText = normalizeText(originalText);
const aliasMap = {
  help: 'help',
  queue: 'list_tickets',
  tickets: 'list_tickets',
  ticketlist: 'list_tickets',
  'list-tickets': 'list_tickets',
  list_tickets: 'list_tickets',
  members: 'members',
  member: 'members',
  pending: 'members',
  ticket: 'get_ticket',
  'get-ticket': 'get_ticket',
  get_ticket: 'get_ticket',
  tracking: 'tracking_url',
  track: 'tracking_url',
  'tracking-url': 'tracking_url',
  tracking_url: 'tracking_url',
  inventory: 'check_inventory',
  'check-inventory': 'check_inventory',
  check_inventory: 'check_inventory',
  stock: 'check_inventory',
  addorder: 'add_order',
  'add-order': 'add_order',
  add_order: 'add_order',
  'add-member': 'add_member',
  add_member: 'add_member',
  addmember: 'add_member',
  invite: 'add_member',
  'invite-member': 'add_member',
  approve: 'approve_member',
  'approve-member': 'approve_member',
  approve_member: 'approve_member',
  duyet: 'approve_member',
  pheduyet: 'approve_member',
  remove: 'remove_member',
  'remove-member': 'remove_member',
  remove_member: 'remove_member',
  xoa: 'remove_member',
  kick: 'remove_member',
  'add-admin': 'add_admin',
  add_admin: 'add_admin',
  addadmin: 'add_admin',
  promote: 'add_admin',
  'promote-admin': 'add_admin',
  'remove-admin': 'remove_admin',
  remove_admin: 'remove_admin',
  removeadmin: 'remove_admin',
  demote: 'remove_admin',
  'demote-admin': 'remove_admin',
  reject: 'reject_ticket',
  'reject-ticket': 'reject_ticket',
  reject_ticket: 'reject_ticket',
};

const extractTicketId = (value) => {
  const rawValue = String(value ?? '').trim();
  if (!rawValue) return null;
  const directNumber = Number(rawValue);
  if (Number.isInteger(directNumber) && directNumber > 0) return directNumber;
  const match = rawValue.match(/(?:^|\b)(?:t\s*-?\s*)?(\d+)(?:\b|$)/i);
  if (!match) return null;
  const parsedNumber = Number(match[1]);
  return Number.isInteger(parsedNumber) && parsedNumber > 0 ? parsedNumber : null;
};

const extractRole = (value) => {
  const rawValue = normalizeText(value);
  if (!rawValue) return '';
  if (rawValue === 'viewer') return 'viewer';
  if (/^sales?$/.test(rawValue)) return 'sales';
  if (rawValue === 'manager') return 'manager';
  return '';
};

const extractLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}]/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';
  const fillerTokens = new Set([
    'phe', 'duyet', 'approve', 'help', 'xem', 'check', 'ticket', 'don', 'member', 'thanh', 'vien',
    'them', 'moi', 'vao', 'nhom', 'group', 'link', 'giup', 'dum', 'cho', 'kich', 'hoat', 'mo',
    'quyen', 'ban', 'nay', 'nhe', 'nha', 'di', 'voi', 'dang', 'nguoi', 'ten', 'xoa', 'remove',
    'kick', 'duoi', 'dua', 'ra', 'khoi', 'out', 'pho', 'admin', 'quan', 'tri', 'bo', 'nhiem',
    'lam', 'go', 'ha', 'deputy', 'cap', 'len', 'cua'
  ]);
  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (['viewer', 'sales', 'manager'].includes(normalizedToken)) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });
  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractTrackingLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}]/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';

  const fillerTokens = new Set([
    'tracking', 'track', 'url', 'link', 'lay', 'cho', 'toi', 'xin', 'gui', 'giup', 'dum', 'nhe', 'nha',
    'tra', 'cuu', 'lich', 'trinh', 'van', 'don', 'ma', 'giao', 'hang', 'nhanh', 'cua', 'xem', 'check',
    'kiem', 'tra', 'order', 'donhang', 'shipping', 'do', 'nay', 'kia', 'no', 'cai', 'moi', 'nhat',
    'gan', 'truoc', 'vua', 'roi', 'ticket', 'case', 'lead', 've', 'yeu', 'cau'
  ]);

  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });

  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractInventoryLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}]/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';

  const fillerTokens = new Set([
    'check', 'kiem', 'tra', 'ton', 'kho', 'con', 'hang', 'khong', 'ko', 'hong', 'het', 'chua',
    'lay', 'xem', 'giup', 'dum', 'cho', 'toi', 'xin', 'nhe', 'nha', 'di', 'voi', 'co', 'ma', 'mau',
    'nay', 'kia', 'do', 'cua', 'shop', 'inventory', 'stock', 'san', 'pham', 'sp'
  ]);

  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });

  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractReason = (value, ticketId) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}]/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';
  const ticketText = String(ticketId || '').trim();
  const fillerTokens = new Set(['reject', 'tu', 'choi', 'xem', 'tat', 'ca', 'danh', 'sach', 'ticket', 'don', 'ma', 'lenh', 't']);
  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    if (ticketText && normalizedToken === ticketText) return false;
    if (ticketText && normalizedToken === ('t' + ticketText)) return false;
    return true;
  });
  return filteredTokens.join(' ').trim();
};

const helpPatterns = [/(^|\s)help(\s|$)/, /huong dan/, /co lenh gi/, /xem lenh/, /menu/];
const trackingPatterns = [
  /tracking/,
  /track/,
  /url tracking/,
  /link tracking/,
  /lich trinh/,
  /tra cuu van don/,
  /ma van don/,
  /link van chuyen/,
  /kiem tra giao hang/
];
const inventoryPatterns = [
  /ton kho/,
  /kiem tra ton kho/,
  /check ton kho/,
  /con hang/,
  /het hang/,
  /con size/,
  /stock/,
  /inventory/,
  /size\s*\d+(?:[.,]\d+)?\s+(?:con|het)/,
  /hang nay con khong/,
  /san pham nay con khong/
];
const listTicketPatterns = [/^xem tat ca$/, /^tat ca$/, /^xem tat ca(?: cac)?(?: (?:don|ticket|ve|lead|yeu cau|case))?$/, /^tat ca(?: cac)?(?: (?:don|ticket|ve|lead|yeu cau|case))?$/, /danh sach (?:ticket|don|ve|lead|yeu cau|case)/, /xem het(?: cac)? (?:don|ticket|ve|lead|yeu cau|case)/, /xem toan bo(?: cac)? (?:don|ticket|ve|lead|yeu cau|case)/, /list (?:ticket|don|ve|lead|yeu cau|case)/, /(?:dang co|hien co|con|co) (?:ticket|don|ve|lead|yeu cau|case) nao(?: khong)?/, /(?:dang co|hien co|con|co) (?:khach|khach hang) nao(?: can| de| dang)? ?(?:xu ly|goi|follow|chot|mo|pending)?(?: khong)?/, /(?:khach|khach hang|lead|case) nao (?:can|de|dang) ?(?:xu ly|goi|follow|chot|mo|pending)/, /co gi can (?:xu ly|goi|follow|chot)/, /co gi moi/, /co gi dang mo/];
const membersPatterns = [/xem thanh vien/, /danh sach thanh vien/, /danh sach member/, /member cho duyet/, /pending member/, /ai dang cho duyet/, /xem pending/, /xem member/];
const addMemberPatterns = [/them thanh vien/, /moi thanh vien/, /add member/, /invite member/, /moi vao nhom/, /them nguoi vao nhom/, /link vao nhom/, /cach them thanh vien/];
const approvePatterns = [/(^|\s)phe duyet(\s|$)/, /duyet member/, /duyet thanh vien/, /approve member/, /approve thanh vien/, /cho vao/, /kich hoat member/, /kich hoat thanh vien/, /^duyet(\s|$)/];
const addAdminPatterns = [/them pho nhom/, /lam pho nhom/, /bo nhiem pho nhom/, /len pho nhom/, /them admin/, /add admin/, /them quan tri/, /cap quyen pho nhom/];
const removeAdminPatterns = [/xoa pho nhom/, /go pho nhom/, /bo pho nhom/, /ha pho nhom/, /xoa admin/, /bo admin/, /remove admin/, /remove deputy/, /go quyen pho nhom/, /bo quyen pho nhom/, /ha quyen pho nhom/];
const removePatterns = [/(^|\s)xoa(\s|$)/, /xoa thanh vien/, /xoa member/, /xoa khoi nhom/, /dua ra khoi nhom/, /duoi khoi nhom/, /remove member/, /remove user/, /kick member/, /kick khoi nhom/];
const rejectPatterns = [/(^|\s)reject(\s|$)/, /tu choi/, /loai bo lead/, /loai lead/, /huy lead/];
const getTicketPatterns = [/xem (?:ticket|don|ve|lead|yeu cau)/, /check (?:ticket|don|ve|lead|yeu cau)/, /(?:ticket|don|ve|lead|yeu cau) ao/, /chi tiet (?:ticket|don|ve|lead|yeu cau)/, /thong tin (?:ticket|don|ve|lead|yeu cau)/, /trang thai (?:ticket|don|ve|lead|yeu cau)/, /lay thong tin/, /co (?:don|ticket|ve|lead|yeu cau)/, /(?:ticket|don|ve|lead|yeu cau) t/, /check t\s*-?\s*\d+/];

const explicitLocalTicketMatch =
  originalText.match(/(?:^|\b)(?:ticket|case|lead|ve|yeu cau)\s*(?:t\s*[-:#]?\s*)?(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)t\s*[-:#]?\s*(\d+)(?:\b|$)/i);
const explicitLocalTicketId = explicitLocalTicketMatch ? extractTicketId(explicitLocalTicketMatch[0]) : null;

const ticketMatchFromText =
  originalText.match(/(?:^|\b)(?:ticket|don|ve|lead|yeu cau|ma|lenh)?\s*t\s*[-:#]?\s*(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)(?:ticket|don|ve|lead|yeu cau)\s*[-:#]?\s*(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)t\s*[-:#]?\s*(\d+)(?:\b|$)/i);
const ticketIdFromText = ticketMatchFromText ? extractTicketId(ticketMatchFromText[0]) : null;
const looseNumberMatch = originalText.match(/(?:^|\s)(\d+)(?:\s|$)/);
const looseTicketIdFromText = looseNumberMatch ? extractTicketId(looseNumberMatch[1]) : null;

let toolName = aliasMap[rawSlashCommand] || 'unknown';
let routeSource = isSlashCommand ? 'draft_slash' : 'draft_heuristic';
let ticketId = null;
let lookupValue = '';
let roleValue = '';
let reasonText = '';
let commandArgsText = '';
let argsJson = [];
let ticketRefRaw = '';
let replyText = '';
let shouldRoute = false;

if (isSlashCommand) {
  const firstArg = String(slashArgs[0] || '').trim();
  const secondArg = String(slashArgs[1] || '').trim();
  if (toolName === 'list_tickets') {
    shouldRoute = true;
  } else if (toolName === 'get_ticket') {
    ticketId = extractTicketId(firstArg);
    if (ticketId) {
      shouldRoute = true;
      lookupValue = String(ticketId);
      commandArgsText = String(ticketId);
      argsJson = [String(ticketId)];
      ticketRefRaw = 'T-' + ticketId;
    } else {
      replyText = 'Bạn muốn xem ticket nào?';
    }
  } else if (toolName === 'tracking_url') {
    const rawTrackingArg = firstMentionUserId || slashArgText || firstArg;
    ticketId = explicitLocalTicketId || (/^t\s*-?\s*\d+$/i.test(rawTrackingArg) ? extractTicketId(rawTrackingArg) : null);
    lookupValue = ticketId ? '' : (extractTrackingLookup(rawTrackingArg) || (/^\d{6,}$/.test(normalizeText(rawTrackingArg)) ? normalizeText(rawTrackingArg) : ''));
    if (ticketId || lookupValue) {
      shouldRoute = true;
      commandArgsText = ticketId ? ('T-' + ticketId) : lookupValue;
      argsJson = commandArgsText ? [commandArgsText] : [];
      ticketRefRaw = ticketId ? ('T-' + ticketId) : '';
    } else {
      replyText = 'Bạn muốn lấy tracking cho đơn nào?';
    }
  } else if (toolName === 'check_inventory') {
    const rawInventoryArg = slashArgText || firstArg;
    ticketId = explicitLocalTicketId || (/^t\s*-?\s*\d+$/i.test(rawInventoryArg) ? extractTicketId(rawInventoryArg) : null);
    lookupValue = ticketId ? '' : extractInventoryLookup(rawInventoryArg);
    if (ticketId || lookupValue) {
      shouldRoute = true;
      commandArgsText = ticketId ? ('T-' + ticketId) : lookupValue;
      argsJson = commandArgsText ? [commandArgsText] : [];
      ticketRefRaw = ticketId ? ('T-' + ticketId) : '';
    } else {
      replyText = 'Bạn muốn check tồn kho mẫu nào?';
    }
  } else if (toolName === 'add_order') {
    ticketId = explicitLocalTicketId || extractTicketId(firstArg) || extractTicketId(secondArg) || extractTicketId(slashArgText);
    shouldRoute = true;
    lookupValue = slashArgText;
    commandArgsText = slashArgText;
    argsJson = slashArgs;
    ticketRefRaw = ticketId ? ('T-' + ticketId) : '';
  } else if (toolName === 'approve_member') {
    shouldRoute = true;
    lookupValue = firstMentionUserId || firstArg;
    roleValue = secondArg ? extractRole(secondArg) : '';
    commandArgsText = [lookupValue, roleValue].filter(Boolean).join(' ').trim();
    argsJson = [lookupValue, roleValue].filter(Boolean);
  } else if (['remove_member', 'add_member', 'add_admin', 'remove_admin'].includes(toolName)) {
    shouldRoute = true;
    lookupValue = firstMentionUserId || slashArgText || firstArg;
    commandArgsText = lookupValue;
    argsJson = lookupValue ? [lookupValue] : [];
  } else if (toolName === 'reject_ticket') {
    ticketId = extractTicketId(firstArg);
    reasonText = slashArgs.slice(1).join(' ').trim();
    if (!ticketId) {
      replyText = 'Thiếu ticket_id. Ví dụ: /reject 123 sai số.';
    } else if (!reasonText) {
      replyText = 'Thiếu lý do reject. Ví dụ: /reject 123 sai số.';
    } else {
      shouldRoute = true;
      lookupValue = String(ticketId);
      commandArgsText = [String(ticketId), reasonText].filter(Boolean).join(' ').trim();
      argsJson = [String(ticketId), reasonText];
      ticketRefRaw = 'T-' + ticketId;
    }
  } else if (toolName === 'help' || toolName === 'members') {
    shouldRoute = true;
    commandArgsText = slashArgs.join(' ').trim();
    argsJson = slashArgs;
  } else {
    replyText = rawSlashCommand ? ('Không nhận ra lệnh /' + rawSlashCommand + '.') : 'Dùng /help.';
  }
} else {
  const hasAny = (patterns) => patterns.some((pattern) => pattern.test(normalizedText));
  if (hasAny(helpPatterns)) {
    toolName = 'help';
    shouldRoute = true;
  } else if (hasAny(trackingPatterns)) {
    toolName = 'tracking_url';
    ticketId = explicitLocalTicketId;
    lookupValue = ticketId ? '' : (firstMentionUserId || extractTrackingLookup(originalText) || (/^\d{6,}$/.test(normalizedText) ? normalizedText : ''));
    if (ticketId || lookupValue) {
      shouldRoute = true;
      commandArgsText = ticketId ? ('T-' + ticketId) : lookupValue;
      argsJson = commandArgsText ? [commandArgsText] : [];
      ticketRefRaw = ticketId ? ('T-' + ticketId) : '';
    } else {
      replyText = 'Bạn muốn lấy tracking cho đơn nào?';
    }
  } else if (hasAny(inventoryPatterns)) {
    toolName = 'check_inventory';
    ticketId = explicitLocalTicketId;
    lookupValue = ticketId ? '' : extractInventoryLookup(originalText);
    if (ticketId || lookupValue) {
      shouldRoute = true;
      commandArgsText = ticketId ? ('T-' + ticketId) : lookupValue;
      argsJson = commandArgsText ? [commandArgsText] : [];
      ticketRefRaw = ticketId ? ('T-' + ticketId) : '';
    } else {
      replyText = 'Bạn muốn check tồn kho mẫu nào?';
    }
  } else if (hasAny(listTicketPatterns)) {
    toolName = 'list_tickets';
    shouldRoute = true;
  } else if (hasAny(membersPatterns)) {
    toolName = 'members';
    shouldRoute = true;
  } else if (hasAny(addAdminPatterns)) {
    toolName = 'add_admin';
    lookupValue = firstMentionUserId || extractLookup(originalText);
    commandArgsText = lookupValue;
    argsJson = lookupValue ? [lookupValue] : [];
    shouldRoute = true;
  } else if (hasAny(removeAdminPatterns)) {
    toolName = 'remove_admin';
    lookupValue = firstMentionUserId || extractLookup(originalText);
    commandArgsText = lookupValue;
    argsJson = lookupValue ? [lookupValue] : [];
    shouldRoute = true;
  } else if (hasAny(addMemberPatterns)) {
    toolName = 'add_member';
    lookupValue = firstMentionUserId || extractLookup(originalText);
    commandArgsText = lookupValue;
    argsJson = lookupValue ? [lookupValue] : [];
    shouldRoute = true;
  } else if (hasAny(approvePatterns)) {
    toolName = 'approve_member';
    lookupValue = firstMentionUserId || extractLookup(originalText);
    roleValue = extractRole(originalText) || '';
    commandArgsText = [lookupValue, roleValue].filter(Boolean).join(' ').trim();
    argsJson = [lookupValue, roleValue].filter(Boolean);
    shouldRoute = true;
  } else if (hasAny(removePatterns)) {
    toolName = 'remove_member';
    lookupValue = firstMentionUserId || extractLookup(originalText);
    commandArgsText = lookupValue;
    argsJson = lookupValue ? [lookupValue] : [];
    shouldRoute = true;
  } else if (hasAny(rejectPatterns)) {
    toolName = 'reject_ticket';
    ticketId = ticketIdFromText ?? looseTicketIdFromText;
    if (!ticketId) {
      replyText = 'Thiếu ticket_id. Ví dụ: /reject 123 sai số.';
    } else {
      reasonText = extractReason(originalText, ticketId);
      if (!reasonText) {
        replyText = 'Thiếu lý do reject. Ví dụ: /reject 123 sai số.';
      } else {
        shouldRoute = true;
      }
    }
  } else if (hasAny(getTicketPatterns) || /(^|\s)(ticket|don|ve|lead|yeu cau)(\s|$)/.test(normalizedText)) {
    toolName = 'get_ticket';
    ticketId = ticketIdFromText ?? looseTicketIdFromText;
    if (ticketId) {
      shouldRoute = true;
    } else {
      replyText = 'Bạn muốn xem ticket nào?';
    }
  }

  if (toolName === 'get_ticket' && ticketId) {
    lookupValue = String(ticketId);
    commandArgsText = String(ticketId);
    argsJson = [String(ticketId)];
    ticketRefRaw = 'T-' + ticketId;
  }
  if (toolName === 'reject_ticket' && ticketId && reasonText) {
    lookupValue = String(ticketId);
    commandArgsText = [String(ticketId), reasonText].filter(Boolean).join(' ').trim();
    argsJson = [String(ticketId), reasonText];
    ticketRefRaw = 'T-' + ticketId;
  }
}

const needsAiRouter = true;

return [{
  json: {
    ...$json,
    route_source: routeSource,
    command_text: originalText,
    tool_name: toolName,
    command_name: toolName,
    command_args_text: commandArgsText,
    args_json: argsJson,
    role_value: roleValue,
    reason_text: reasonText,
    ticket_id: ticketId,
    lookup_value: lookupValue,
    ticket_ref_raw: ticketRefRaw,
    reply_text: replyText,
    should_route_command: shouldRoute,
    needs_ai_router: needsAiRouter,
  },
}];

