parameters.jsCode:
const base = $('Set Zalo AI Intent Input').first().json;
const raw = $json.output ?? $json.text ?? $json;

let text = '';
if (typeof raw === 'string') {
  text = raw.trim();
} else {
  text = JSON.stringify(raw);
}

text = text
  .replace(/^\`\`\`json\s*/i, '')
  .replace(/^\`\`\`\s*/i, '')
  .replace(/\s*\`\`\`$/i, '')
  .trim();

let parsed = {};
try {
  parsed = JSON.parse(text);
} catch (error) {
  parsed = {};
}

if (parsed && typeof parsed.output === 'object' && parsed.output !== null) {
  parsed = parsed.output;
}

const parseJson = (value) => {
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
};

const allowedTools = new Set(['help', 'list_tickets', 'get_ticket', 'tracking_url', 'check_inventory', 'members', 'add_member', 'approve_member', 'remove_member', 'add_admin', 'remove_admin', 'reject_ticket', 'add_order']);
const originalText = String(base.text || '').trim();
const mentionUserIds = [...new Set([
  ...((Array.isArray(base.mention_user_ids) ? base.mention_user_ids : []).map((value) => String(value || '').trim()).filter(Boolean)),
  ...Array.from(originalText.matchAll(/(?:\[@\s*|@)(\d{5,})(?:\])?/g), (match) => String(match[1] || '').trim()).filter(Boolean),
])];

const recentTicketActionsRaw = parseJson(base.recent_ticket_actions);
const recentTicketActions = Array.isArray(recentTicketActionsRaw) ? recentTicketActionsRaw : [];
const openTicketsRaw = parseJson(base.open_tickets);
const openTickets = Array.isArray(openTicketsRaw) ? openTicketsRaw : [];

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'd')
  .toLowerCase()
  .replace(/[^a-z0-9\s\/-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const compressText = (value) => normalizeText(value).replace(/\s+/g, '');
const onlyDigits = (value) => String(value || '').replace(/[^\d]/g, '');

const extractTicketId = (value) => {
  const rawValue = String(value ?? '').trim();
  if (!rawValue) return null;
  const directNumber = Number(rawValue);
  if (Number.isInteger(directNumber) && directNumber > 0) return directNumber;
  const match = rawValue.match(/(?:^|\b)(?:t\s*-?\s*)?(\d+)(?:\b|$)/i);
  if (!match) return null;
  const parsedNumber = Number(match[1]);
  return Number.isInteger(parsedNumber) && parsedNumber > 0 ? parsedNumber : null;
};

const extractRole = (value) => {
  const rawValue = normalizeText(value);
  if (!rawValue) return '';
  if (rawValue === 'viewer') return 'viewer';
  if (/^sales?$/.test(rawValue)) return 'sales';
  if (rawValue === 'manager') return 'manager';
  return '';
};

const normalizeTicketScope = (value) => {
  const rawValue = compressText(value);
  if (!rawValue) return '';
  if (['all', 'tatca', 'toanbo', 'het', 'full'].includes(rawValue)) return 'all';
  if (['open', 'mo', 'active', 'dangxuly', 'pending', 'current'].includes(rawValue)) return 'open';
  return '';
};

const deriveTicketScope = (value) => {
  const normalizedValue = normalizeText(value);
  if (!normalizedValue) return '';
  if (/(^|\s)(xem tat ca|tat ca|toan bo|xem het|liet ke het)(\s|$)/.test(normalizedValue)) return 'all';
  if (/danh sach tat ca/.test(normalizedValue)) return 'all';
  if (/(^|\s)(dang co|hien co|con|co)(\s|$)/.test(normalizedValue)) return 'open';
  if (/(co gi can|co gi dang|co gi moi|ticket mo|lead mo|case mo|khach nao can)/.test(normalizedValue)) return 'open';
  return '';
};

const extractLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}"']/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';

  const fillerTokens = new Set([
    'phe', 'duyet', 'approve', 'help', 'xem', 'check', 'ticket', 'don', 'member', 'thanh', 'vien',
    'them', 'moi', 'vao', 'nhom', 'group', 'link', 'giup', 'dum', 'cho', 'kich', 'hoat', 'mo',
    'quyen', 'ban', 'nay', 'nhe', 'nha', 'di', 'voi', 'dang', 'cho', 'nguoi', 'ten', 'anh', 'chi',
    'em', 'oi', 'giu', 'ho', 'gium', 'a', 'ah', 'ha', 'xoa', 'remove', 'kick', 'duoi', 'dua',
    'ra', 'khoi', 'out', 'pho', 'admin', 'quan', 'tri', 'bo', 'nhiem', 'lam', 'go', 'ha',
    'deputy', 'cap', 'len', 'cua'
  ]);

  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (['viewer', 'sales', 'manager'].includes(normalizedToken)) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });

  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractTrackingLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}"']/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';

  const fillerTokens = new Set([
    'tracking', 'track', 'url', 'link', 'lay', 'cho', 'toi', 'xin', 'gui', 'giup', 'dum', 'nhe', 'nha',
    'tra', 'cuu', 'lich', 'trinh', 'van', 'don', 'ma', 'giao', 'hang', 'nhanh', 'cua', 'xem', 'check',
    'kiem', 'tra', 'order', 'donhang', 'shipping', 'do', 'nay', 'kia', 'no', 'cai', 'moi', 'nhat',
    'gan', 'truoc', 'vua', 'roi', 'ticket', 'case', 'lead', 've', 'yeu', 'cau'
  ]);

  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });

  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractInventoryLookup = (value) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}"']/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';

  const fillerTokens = new Set([
    'check', 'kiem', 'tra', 'ton', 'kho', 'con', 'hang', 'khong', 'ko', 'hong', 'het', 'chua',
    'lay', 'xem', 'giup', 'dum', 'cho', 'toi', 'xin', 'nhe', 'nha', 'di', 'voi', 'co', 'ma', 'mau',
    'nay', 'kia', 'do', 'cua', 'shop', 'inventory', 'stock', 'san', 'pham', 'sp'
  ]);

  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    return true;
  });

  return filteredTokens
    .map((token) => {
      const normalizedToken = normalizeText(token);
      return /^\d+$/.test(normalizedToken) ? normalizedToken : token;
    })
    .join(' ')
    .trim();
};

const extractReason = (value, ticketId) => {
  const originalTokens = String(value || '')
    .replace(/[,:;.!?()\[\]{}"']/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!originalTokens.length) return '';
  const ticketText = String(ticketId || '').trim();
  const fillerTokens = new Set(['reject', 'tu', 'choi', 'xem', 'tat', 'ca', 'danh', 'sach', 'ticket', 'don', 'ma', 'lenh', 't', 'no', 'do', 'cai', 'nay']);
  const filteredTokens = originalTokens.filter((token) => {
    const normalizedToken = normalizeText(token);
    if (!normalizedToken) return false;
    if (fillerTokens.has(normalizedToken)) return false;
    if (ticketText && normalizedToken === ticketText) return false;
    if (ticketText && normalizedToken === ('t' + ticketText)) return false;
    return true;
  });
  return filteredTokens.join(' ').trim();
};

const buildLookupCandidates = (...values) => {
  const candidates = [];
  const seen = new Set();

  const pushCandidate = (value) => {
    const rawValue = String(value || '').trim();
    if (!rawValue) return;

    const variants = [extractLookup(rawValue), rawValue];
    for (const variant of variants) {
      const candidate = String(variant || '').trim();
      const normalized = normalizeText(candidate);
      const compressed = compressText(candidate);
      if (!normalized || !compressed) continue;
      if (['viewer', 'sales', 'manager'].includes(normalized)) continue;
      if (seen.has(compressed)) continue;
      seen.add(compressed);
      candidates.push(candidate);
    }
  };

  for (const value of values.flat()) {
    pushCandidate(value);
  }

  return candidates;
};

const aiToolNameRaw = String(parsed.tool_name || parsed.command_name || 'unknown').trim().toLowerCase();
const aiToolName = allowedTools.has(aiToolNameRaw) ? aiToolNameRaw : 'unknown';
const aiShouldRoute = parsed.should_route === true;
const aiReplyText = String(parsed.reply_text || '').trim();
const aiLookupValue = String(parsed.lookup_value || '').trim();
const aiRoleValue = extractRole(parsed.role_value);
const aiReasonText = String(parsed.reason_text || '').trim();
const aiTicketScope = normalizeTicketScope(parsed.ticket_scope);
const aiCityQuery = String(parsed.city_query || '').trim();
const aiDistrictQuery = String(parsed.district_query || '').trim();
const aiMaxResults = Math.max(1, Math.min(10, Number(parsed.max_results || 5) || 5));

const draftToolNameRaw = String(base.tool_name || base.command_name || 'unknown').trim().toLowerCase();
const draftToolName = allowedTools.has(draftToolNameRaw) ? draftToolNameRaw : 'unknown';
const draftReplyText = String(base.reply_text || '').trim();
const draftLookupValue = String(base.lookup_value || '').trim();
const draftRoleValue = extractRole(base.role_value);
const draftReasonText = String(base.reason_text || '').trim();
const draftShouldRoute = base.should_route_command === true && draftToolName !== 'unknown';
const draftTicketScope = normalizeTicketScope(base.ticket_scope);

let ticketIdFromAI = extractTicketId(parsed.ticket_id);
const ticketIdFromDraft = extractTicketId(base.ticket_id);
const ticketMatchFromText =
  originalText.match(/(?:^|\b)(?:ticket|don|ve|lead|yeu cau|case|ma|lenh)?\s*t\s*[-:#]?\s*(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)(?:ticket|don|ve|lead|yeu cau|case)\s*[-:#]?\s*(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)t\s*[-:#]?\s*(\d+)(?:\b|$)/i);
const ticketIdFromText = ticketMatchFromText ? extractTicketId(ticketMatchFromText[0]) : null;
const explicitLocalTicketMatch =
  originalText.match(/(?:^|\b)(?:ticket|case|lead|ve|yeu cau)\s*(?:t\s*[-:#]?\s*)?(\d+)(?:\b|$)/i) ||
  originalText.match(/(?:^|\b)t\s*[-:#]?\s*(\d+)(?:\b|$)/i);
const explicitLocalTicketId = explicitLocalTicketMatch ? extractTicketId(explicitLocalTicketMatch[0]) : null;
const looseNumberMatch = originalText.match(/(?:^|\s)(\d+)(?:\s|$)/);
const looseTicketIdFromText = looseNumberMatch ? extractTicketId(looseNumberMatch[1]) : null;
const latestTicketIdFromContext =
  extractTicketId(base.latest_ticket_id) ??
  extractTicketId(base.latest_open_ticket_id) ??
  extractTicketId(recentTicketActions[0]?.ticket_id) ??
  extractTicketId(openTickets[0]?.id);
const singleOpenTicketId = openTickets.length === 1 ? extractTicketId(openTickets[0]?.id) : null;
const findOpenTicketProduct = (candidateTicketId) => {
  const ticketId = extractTicketId(candidateTicketId);
  if (!ticketId) return '';
  const matchedTicket = openTickets.find((item) => extractTicketId(item?.id) === ticketId);
  return String(matchedTicket?.products_interested || matchedTicket?.need_summary || '').trim();
};

let ticketId = ticketIdFromAI ?? ticketIdFromDraft ?? ticketIdFromText ?? looseTicketIdFromText;
const normalizedOriginalText = normalizeText(originalText);
const derivedTicketScope = deriveTicketScope(originalText);
const contextTicketReferencePatterns = [
  /(?:ticket|don|ve|lead|yeu cau|case)\s+(?:do|nay|kia|moi nhat|gan nhat|vua roi|truoc do)/,
  /(?:^|\s)(?:xem|check|mo|lay|chi tiet|thong tin|trang thai)\s+(?:ticket|don|ve|lead|yeu cau|case)\s+(?:do|nay|kia|moi nhat|gan nhat|vua roi|truoc do)(?:\s|$)/,
  /(?:^|\s)(?:ticket|don|ve|lead|yeu cau|case)\s+(?:moi nhat|gan nhat)(?:\s|$)/
];
const contextRejectPatterns = [
  /(?:^|\s)(?:reject|tu choi|loai bo|huy)(?:\s|$)/,
  /(?:^|\s)(?:reject|tu choi|loai bo|huy)\s+(?:ticket|don|ve|lead|yeu cau|case|no|do|cai do|cai nay)(?:\s|$)/
];
const contextTrackingPatterns = [
  /(?:tracking|link tracking|url tracking|lich trinh)\s+(?:ticket|don|ve|lead|case)\s+(?:do|nay|kia|moi nhat|gan nhat|vua roi|truoc do)/,
  /(?:tracking|link tracking|url tracking|lich trinh)\s+(?:ticket|don|ve|lead|case)\s+(?:moi nhat|gan nhat)(?:\s|$)/
];
const contextTicketRequested = contextTicketReferencePatterns.some((pattern) => pattern.test(normalizedOriginalText));
const semanticListTicketPatterns = [
  /(?:^|\s)(?:xem|check|list|danh sach)?\s*(?:tat ca|toan bo|het)(?:\s|$)/,
  /(?:^|\s)(?:dang co|hien co|con|co)\s+(?:ticket|don|ve|lead|yeu cau|case)\s+nao(?:\s+khong)?(?:\s|$)/,
  /danh sach\s+(?:ticket|don|ve|lead|yeu cau|case)/,
  /xem\s+(?:het|toan bo)?\s*(?:cac\s+)?(?:ticket|don|ve|lead|yeu cau|case)/,
  /co gi can\s+(?:xu ly|goi|follow|chot)/,
  /co gi moi/,
  /co gi dang mo/
];
const semanticWorkQueuePatterns = [
