const row = $input.first()?.json || {};

const safeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const compactArray = (value) => Array.isArray(value) ? value.filter((item) => item && typeof item === 'object') : [];
const items = compactArray(row.items);
const availableItems = compactArray(row.available_items).length ? compactArray(row.available_items) : items.filter((item) => Number(item.available || 0) > 0);
const productQuery = safeText(base.product_query || base.lookup_value || row.product_query || '');
const availableCount = Number(row.available_count ?? availableItems.length);
const totalCount = Number(row.total ?? items.length);

const formatItem = (item) => {
  const name = safeText(item.name || item.full_name || item.product_name || item.code || '');
  const code = safeText(item.code || item.sku || '');
  const available = Number(item.available ?? item.available_quantity ?? item.remain ?? item.stock ?? 0);
  const parts = [];
  if (name) parts.push(name);
  if (code && code !== name) parts.push(code);
  if (Number.isFinite(available)) parts.push('còn ' + available);
  return parts.filter(Boolean).join(' | ');
};

let replyText = '';
let auditActionType = 'inventory_checked';

if (row.ok === false) {
  replyText = safeText(row.message || row.error || 'Không check tồn kho được.');
  auditActionType = 'inventory_check_failed';
} else if (availableCount > 0 || availableItems.length > 0) {
  const lines = [(productQuery || 'Sản phẩm') + ': còn hàng.'];
  const detailLines = availableItems.map(formatItem).filter(Boolean).slice(0, 5);
  if (detailLines.length) lines.push(...detailLines);
  if (!detailLines.length && Number.isFinite(totalCount)) lines.push('Có ' + totalCount + ' kết quả phù hợp.');
  replyText = lines.join('\n');
} else if (row.ok === true) {
  replyText = (productQuery || 'Sản phẩm') + ': hiện không có hàng.';
} else {
  replyText = 'Không check tồn kho được.';
  auditActionType = 'inventory_check_failed';
}

return [{
  json: {
    ...base,
    ...row,
    reply_text: replyText,
    audit_action_type: auditActionType,
    inventory_ok: row.ok ?? null,
    inventory_total: Number.isFinite(totalCount) ? totalCount : items.length,
    inventory_available_count: Number.isFinite(availableCount) ? availableCount : availableItems.length,
    handoff_queue_id: base.ticket_id || '',
  },
}];

const base = $('If Inventory Route').first().json;
const row = $input.first()?.json || {};

const productQuery = String(base.product_query || base.lookup_value || '').trim();
const maxResultsRaw = Number(base.max_results || 5);
const maxResults = Math.max(1, Math.min(10, Number.isFinite(maxResultsRaw) ? maxResultsRaw : 5));
const nhanhAccessToken = String(row.nhanh_access_token || '').trim();
const nhanhAppId = Number(row.nhanh_app_id || 0) || 0;
const nhanhBusinessId = Number(row.nhanh_business_id || 0) || 0;

let replyText = '';
let auditActionType = 'inventory_checked';
let canQueryInventory = false;
let inventoryUrl = '';
let inventoryRequestBody = null;

if (!productQuery) {
  replyText = 'Bạn muốn check tồn kho mẫu nào?';
  auditActionType = 'inventory_check_guided';
} else if (!nhanhAccessToken || !nhanhAppId || !nhanhBusinessId) {
  replyText = 'Thiếu cấu hình Nhanh.';
  auditActionType = 'inventory_check_failed';
} else {
  canQueryInventory = true;
  inventoryUrl = `https://pos.open.nhanh.vn/v3.0/product/inventory?appId=${nhanhAppId}&businessId=${nhanhBusinessId}`;
  inventoryRequestBody = {
    filters: {
      name: productQuery,
    },
    paginator: {
      size: maxResults,
    },
    dataOptions: {},
  };
}

return [{
  json: {
    ...base,
    ...row,
    nhanh_access_token: nhanhAccessToken,
    nhanh_app_id: nhanhAppId,
    nhanh_business_id: nhanhBusinessId,
    product_query: productQuery,
    max_results: maxResults,
    can_query_inventory: canQueryInventory,
    inventory_url: inventoryUrl,
    inventory_request_body: inventoryRequestBody,
    reply_text: replyText,
    audit_action_type: auditActionType,
  },
}];

const base = $('Code Build Inventory Query').first().json;
const payload = $input.first()?.json || {};

if (payload.error) {
  return [{
    json: {
      ...base,
      ok: false,
      error_code: 'NHANH_API_ERROR',
      message: String(payload.error || 'Lỗi Nhanh API'),
      total: 0,
      available_count: 0,
      available_items: [],
      items: [],
    },
  }];
}

const root = payload?.data ?? payload?.result ?? payload ?? {};
const rawItems = Array.isArray(root?.products)
  ? root.products
  : Array.isArray(root?.data)
    ? root.data
    : Array.isArray(root)
      ? root
      : [];

const items = rawItems.map((item) => {
  const inventory = item.inventory ?? {};
  return {
    id: item.id ?? item.productId ?? null,
    code: item.code ?? item.productCode ?? '',
    name: item.name ?? '',
    barcode: item.barcode ?? '',
    price: Number(item?.prices?.price ?? 0),
    remain: Number(inventory.remain ?? item.remain ?? 0),
    available: Number(inventory.available ?? item.available ?? 0),
    shipping: Number(inventory.shipping ?? item.shipping ?? 0),
    holding: Number(inventory.holding ?? item.holding ?? 0),
    damaged: Number(inventory.damaged ?? item.damaged ?? item.damage ?? 0),
    depots: Array.isArray(inventory.depots ?? item.depots) ? (inventory.depots ?? item.depots) : [],
  };
}).sort((a, b) => (b.available - a.available) || (b.remain - a.remain) || a.name.localeCompare(b.name, 'vi'));

const availableItems = items.filter((item) => Number(item.available || 0) > 0);

return [{
  json: {
    ...base,
    ok: true,
    total: items.length,
    available_count: availableItems.length,
    available_items: availableItems,
    items,
  },
}];

const base = $('Code Build Inventory Query').first().json;
return [{
  json: {
    ...base,
    ok: false,
    message: String(base.reply_text || 'Không check tồn kho được.').trim(),
    total: 0,
    available_count: 0,
    available_items: [],
    items: [],
  },
}];

const base = $('If AddOrder Route').first().json;
const row = $input.first()?.json || {};
const replyText = String(row.reply_text || base.reply_text || 'Không xử lý được /addorder.').trim();
const auditActionType = String(row.audit_action_type || base.audit_action_type || 'order_draft_replied').trim() || 'order_draft_replied';

return [{
  json: {
    ...base,
    ...row,
    reply_text: replyText,
    audit_action_type: auditActionType,
    handoff_queue_id: row.handoff_queue_id || row.ticket_id || base.ticket_id || '',
    order_draft_id: row.order_draft_id || null,
    order_draft_status: row.order_draft_status || '',
    app_order_id: row.app_order_id || '',
    nhanh_order_id: row.nhanh_order_id || null,
    created_order_tracking_url: row.created_order_tracking_url || '',
  },
}];
